 69→    /// Initializes the protocol config pda. Can only be called once by the
 70→    /// program account keypair.
 71→    pub fn initialize_protocol_config(
 72→        ctx: Context<InitializeProtocolConfig>,
 73→        bump: u8,
 74→        protocol_config: ProtocolConfig,
 75→    ) -> Result<()> {
 76→        ctx.accounts.protocol_config_pda.authority = ctx.accounts.authority.key();
 77→        ctx.accounts.protocol_config_pda.bump = bump;
 78→        check_protocol_config(protocol_config)?;
 79→        ctx.accounts.protocol_config_pda.config = protocol_config;
 80→        Ok(())
 81→    }
 82→
 83→    pub fn update_protocol_config(
 84→        ctx: Context<UpdateProtocolConfig>,
 85→        protocol_config: Option<ProtocolConfig>,
 86→    ) -> Result<()> {
 87→        if let Some(new_authority) = ctx.accounts.new_authority.as_ref() {
 88→            ctx.accounts.protocol_config_pda.authority = new_authority.key();
 89→        }
 90→        if let Some(protocol_config) = protocol_config {
 91→            if protocol_config.genesis_slot != ctx.accounts.protocol_config_pda.config.genesis_slot
 92→            {
 93→                msg!("Genesis slot cannot be changed.");
 94→                return err!(RegistryError::InvalidConfigUpdate);
 95→            }
 96→            if protocol_config.active_phase_length
 97→                != ctx.accounts.protocol_config_pda.config.active_phase_length
 98→            {
 99→                msg!(
100→                    "Active phase length must not be changed, otherwise epochs will repeat {} {}.",
101→                    protocol_config.active_phase_length,
102→                    ctx.accounts.protocol_config_pda.config.active_phase_length
103→                );
104→                return err!(RegistryError::InvalidConfigUpdate);
105→            }
106→            check_protocol_config(protocol_config)?;
107→            ctx.accounts.protocol_config_pda.config = protocol_config;
108→        }
109→        Ok(())
110→    }
