112→    pub fn register_system_program(ctx: Context<RegisterProgram>, bump: u8) -> Result<()> {
113→        let bump = &[bump];
114→        let seeds = [CPI_AUTHORITY_PDA_SEED, bump];
115→        let signer_seeds = &[&seeds[..]];
116→
117→        let accounts = account_compression::cpi::accounts::RegisterProgramToGroup {
118→            authority: ctx.accounts.cpi_authority.to_account_info(),
119→            program_to_be_registered: ctx.accounts.program_to_be_registered.to_account_info(),
120→            system_program: ctx.accounts.system_program.to_account_info(),
121→            registered_program_pda: ctx.accounts.registered_program_pda.to_account_info(),
122→            group_authority_pda: ctx.accounts.group_pda.to_account_info(),
123→        };
124→
125→        let cpi_ctx = CpiContext::new_with_signer(
126→            ctx.accounts.account_compression_program.to_account_info(),
127→            accounts,
128→            signer_seeds,
129→        );
130→
131→        account_compression::cpi::register_program_to_group(cpi_ctx)
132→    }
