192→    /// Registers the forester for the epoch.
193→    /// 1. Only the forester can register herself for the epoch.
194→    /// 2. Protocol config is copied.
195→    /// 3. Epoch account is created if needed.
196→    pub fn register_forester_epoch<'info>(
197→        ctx: Context<'_, '_, '_, 'info, RegisterForesterEpoch<'info>>,
198→        epoch: u64,
199→    ) -> Result<()> {
200→        // Only init if not initialized
201→        if ctx.accounts.epoch_pda.registered_weight == 0 {
202→            (*ctx.accounts.epoch_pda).clone_from(&EpochPda {
203→                epoch,
204→                protocol_config: ctx.accounts.protocol_config.config,
205→                total_work: 0,
206→                registered_weight: 0,
207→            });
208→        }
209→        let current_solana_slot = anchor_lang::solana_program::clock::Clock::get()?.slot;
210→        // Init epoch account if not initialized
211→        let current_epoch = ctx
212→            .accounts
213→            .epoch_pda
214→            .protocol_config
215→            .get_latest_register_epoch(current_solana_slot)?;
216→
217→        if current_epoch != epoch {
218→            return err!(RegistryError::InvalidEpoch);
219→        }
220→        // check that epoch is in registration phase is in process_register_for_epoch
221→        process_register_for_epoch(
222→            &ctx.accounts.authority.key(),
223→            &mut ctx.accounts.forester_pda,
224→            &mut ctx.accounts.forester_epoch_pda,
225→            &mut ctx.accounts.epoch_pda,
226→            current_solana_slot,
227→        )?;
228→        Ok(())
229→    }
