267→    pub fn report_work<'info>(ctx: Context<'_, '_, '_, 'info, ReportWork<'info>>) -> Result<()> {
268→        let current_solana_slot = anchor_lang::solana_program::clock::Clock::get()?.slot;
269→        ctx.accounts
270→            .epoch_pda
271→            .protocol_config
272→            .is_report_work_phase(current_solana_slot, ctx.accounts.epoch_pda.epoch)?;
273→        if ctx.accounts.epoch_pda.epoch != ctx.accounts.forester_epoch_pda.epoch {
274→            return err!(RegistryError::InvalidEpoch);
275→        }
276→        if ctx.accounts.forester_epoch_pda.has_reported_work {
277→            return err!(RegistryError::ForesterAlreadyReportedWork);
278→        }
279→        ctx.accounts.epoch_pda.total_work += ctx.accounts.forester_epoch_pda.work_counter;
280→        ctx.accounts.forester_epoch_pda.has_reported_work = true;
281→        Ok(())
282→    }
