325→    pub fn initialize_state_merkle_tree(
326→        ctx: Context<InitializeMerkleTreeAndQueue>,
327→        bump: u8,
328→        program_owner: Option<Pubkey>,
329→        forester: Option<Pubkey>,
330→        merkle_tree_config: StateMerkleTreeConfig,
331→        queue_config: NullifierQueueConfig,
332→    ) -> Result<()> {
333→        // Program owned trees are disabled
334→        if program_owner.is_some() {
335→            msg!("Program owner must not be defined.");
336→            return err!(RegistryError::ProgramOwnerDefined);
337→        }
338→        // The network fee must be either zero or the same as the protocol config.
339→        // Only trees with a network fee will be serviced by light foresters.
340→        if let Some(network_fee) = merkle_tree_config.network_fee {
341→            if network_fee != ctx.accounts.protocol_config_pda.config.network_fee {
342→                return err!(RegistryError::InvalidNetworkFee);
343→            }
344→            if forester.is_some() {
345→                msg!("Forester pubkey must not be defined for trees serviced by light foresters.");
346→                return err!(RegistryError::ForesterDefined);
347→            }
348→        } else if forester.is_none() {
349→            msg!("Forester pubkey required for trees without a network fee.");
350→            msg!("Trees without a network fee will not be serviced by light foresters.");
351→            return err!(RegistryError::ForesterUndefined);
352→        }
353→
354→        // Unused parameter
355→        if queue_config.network_fee.is_some() {
356→            return err!(RegistryError::InvalidNetworkFee);
357→        }
358→        check_cpi_context(
359→            ctx.accounts
360→                .cpi_context_account
361→                .as_ref()
362→                .unwrap()
363→                .to_account_info(),
364→            &ctx.accounts.protocol_config_pda.config,
365→        )?;
366→        process_initialize_state_merkle_tree(
367→            &ctx,
368→            bump,
369→            0,
370→            program_owner,
371→            forester,
372→            merkle_tree_config,
373→            queue_config,
374→        )?;
375→
376→        process_initialize_cpi_context(
377→            bump,
378→            ctx.accounts.authority.to_account_info(),
379→            ctx.accounts
380→                .cpi_context_account
381→                .as_ref()
382→                .unwrap()
383→                .to_account_info(),
384→            ctx.accounts.merkle_tree.to_account_info(),
385→            ctx.accounts
386→                .light_system_program
387→                .as_ref()
388→                .unwrap()
389→                .to_account_info(),
390→        )
391→    }
