499→    pub fn initialize_batched_state_merkle_tree<'info>(
500→        ctx: Context<'_, '_, '_, 'info, InitializeBatchedStateMerkleTreeAndQueue<'info>>,
501→        bump: u8,
502→        params: Vec<u8>,
503→    ) -> Result<()> {
504→        let params = InitStateTreeAccountsInstructionData::try_from_slice(&params)?;
505→        // Program owned trees are disabled
506→        if params.program_owner.is_some() {
507→            msg!("Program owner must not be defined.");
508→            return err!(RegistryError::ProgramOwnerDefined);
509→        }
510→        if let Some(network_fee) = params.network_fee {
511→            if network_fee != ctx.accounts.protocol_config_pda.config.network_fee {
512→                return err!(RegistryError::InvalidNetworkFee);
513→            }
514→            if params.forester.is_some() {
515→                msg!("Forester pubkey must not be defined for trees serviced by light foresters.");
516→                return err!(RegistryError::ForesterDefined);
517→            }
518→        } else {
519→            return err!(RegistryError::InvalidNetworkFee);
520→        }
521→        check_cpi_context(
522→            ctx.accounts.cpi_context_account.to_account_info(),
523→            &ctx.accounts.protocol_config_pda.config,
524→        )?;
525→
526→        process_initialize_batched_state_merkle_tree(&ctx, bump, params.try_to_vec().unwrap())?;
527→
528→        process_initialize_cpi_context(
529→            bump,
530→            ctx.accounts.authority.to_account_info(),
531→            ctx.accounts.cpi_context_account.to_account_info(),
532→            ctx.accounts.merkle_tree.to_account_info(),
533→            ctx.accounts.light_system_program.to_account_info(),
534→        )
535→    }
