537→    pub fn batch_nullify<'info>(
538→        ctx: Context<'_, '_, '_, 'info, BatchNullify<'info>>,
539→        bump: u8,
540→        data: Vec<u8>,
541→    ) -> Result<()> {
542→        let merkle_tree =
543→            BatchedMerkleTreeAccount::state_from_account_info(&ctx.accounts.merkle_tree)
544→                .map_err(ProgramError::from)?;
545→        check_forester(
546→            &merkle_tree.metadata,
547→            ctx.accounts.authority.key(),
548→            ctx.accounts.merkle_tree.key(),
549→            &mut ctx.accounts.registered_forester_pda,
550→            // Reward for performed work is input queue batch size.
551→            merkle_tree.queue_batches.batch_size,
552→        )?;
553→
554→        process_batch_nullify(&ctx, bump, data)
555→    }
