557→    pub fn batch_append<'info>(
558→        ctx: Context<'_, '_, '_, 'info, BatchAppend<'info>>,
559→        bump: u8,
560→        data: Vec<u8>,
561→    ) -> Result<()> {
562→        let queue_account =
563→            BatchedQueueAccount::output_from_account_info(&ctx.accounts.output_queue)
564→                .map_err(ProgramError::from)?;
565→        let merkle_tree =
566→            BatchedMerkleTreeAccount::state_from_account_info(&ctx.accounts.merkle_tree)
567→                .map_err(ProgramError::from)?;
568→        // Eligibility is checked for the Merkle tree,
569→        // so that the same forester is eligible to
570→        // batch append and batch nullify of the same tree.
571→        check_forester(
572→            &merkle_tree.metadata,
573→            ctx.accounts.authority.key(),
574→            ctx.accounts.merkle_tree.key(),
575→            &mut ctx.accounts.registered_forester_pda,
576→            // Reward for performed work is output queue batch size.
577→            queue_account.batch_metadata.batch_size,
578→        )?;
579→        process_batch_append(&ctx, bump, data)
580→    }
581→
582→    pub fn initialize_batched_address_merkle_tree(
583→        ctx: Context<InitializeBatchedAddressTree>,
584→        bump: u8,
585→        params: Vec<u8>,
586→    ) -> Result<()> {
587→        let params = InitAddressTreeAccountsInstructionData::try_from_slice(&params)?;
588→        // Program owned trees are disabled
589→        if params.program_owner.is_some() {
590→            msg!("Program owner must not be defined.");
591→            return err!(RegistryError::ProgramOwnerDefined);
592→        }
593→        if let Some(network_fee) = params.network_fee {
594→            if network_fee != ctx.accounts.protocol_config_pda.config.address_network_fee {
595→                msg!(
596→                    "ctx.accounts.protocol_config_pda.config.address_network_fee {:?}",
597→                    ctx.accounts.protocol_config_pda.config.address_network_fee
598→                );
599→                msg!("network_fee {:?}", network_fee);
600→                return err!(RegistryError::InvalidNetworkFee);
601→            }
602→            if params.forester.is_some() {
603→                msg!("Forester pubkey must not be defined for trees serviced by light foresters.");
604→                return err!(RegistryError::ForesterDefined);
605→            }
606→        } else {
607→            return err!(RegistryError::InvalidNetworkFee);
608→        }
609→        process_initialize_batched_address_merkle_tree(&ctx, bump, params.try_to_vec()?)
610→    }
611→
612→    pub fn batch_update_address_tree<'info>(
613→        ctx: Context<'_, '_, '_, 'info, BatchUpdateAddressTree<'info>>,
614→        bump: u8,
615→        data: Vec<u8>,
616→    ) -> Result<()> {
617→        let account =
618→            BatchedMerkleTreeAccount::address_from_account_info(&ctx.accounts.merkle_tree)
619→                .map_err(ProgramError::from)?;
620→        check_forester(
621→            &account.metadata,
622→            ctx.accounts.authority.key(),
623→            ctx.accounts.merkle_tree.key(),
624→            &mut ctx.accounts.registered_forester_pda,
625→            account.queue_batches.batch_size,
626→        )?;
627→
628→        process_batch_update_address_tree(&ctx, bump, data)
629→    }
630→
631→    pub fn rollover_batched_address_merkle_tree<'info>(
632→        ctx: Context<'_, '_, '_, 'info, RolloverBatchedAddressMerkleTree<'info>>,
633→        bump: u8,
634→    ) -> Result<()> {
635→        let account = BatchedMerkleTreeAccount::address_from_account_info(
636→            &ctx.accounts.old_address_merkle_tree,
637→        )
638→        .map_err(ProgramError::from)?;
639→        check_forester(
640→            &account.metadata,
641→            ctx.accounts.authority.key(),
642→            ctx.accounts.old_address_merkle_tree.key(),
643→            &mut ctx.accounts.registered_forester_pda,
644→            DEFAULT_WORK_V1,
645→        )?;
646→        process_rollover_batched_address_merkle_tree(&ctx, bump)
647→    }
648→
649→    pub fn rollover_batched_state_merkle_tree<'info>(
650→        ctx: Context<'_, '_, '_, 'info, RolloverBatchedStateMerkleTree<'info>>,
651→        bump: u8,
652→    ) -> Result<()> {
653→        let account =
654→            BatchedMerkleTreeAccount::state_from_account_info(&ctx.accounts.old_state_merkle_tree)
655→                .map_err(ProgramError::from)?;
656→        check_forester(
657→            &account.metadata,
658→            ctx.accounts.authority.key(),
659→            ctx.accounts.old_state_merkle_tree.key(),
660→            &mut ctx.accounts.registered_forester_pda,
661→            DEFAULT_WORK_V1,
662→        )?;
663→        check_cpi_context(
664→            ctx.accounts.cpi_context_account.to_account_info(),
665→            &ctx.accounts.protocol_config_pda.config,
666→        )?;
667→
668→        process_rollover_batched_state_merkle_tree(&ctx, bump)?;
669→
670→        process_initialize_cpi_context(
671→            bump,
672→            ctx.accounts.authority.to_account_info(),
673→            ctx.accounts.cpi_context_account.to_account_info(),
674→            ctx.accounts.new_state_merkle_tree.to_account_info(),
675→            ctx.accounts.light_system_program.to_account_info(),
676→        )
677→    }
678→
679→    pub fn migrate_state<'info>(
680→        ctx: Context<'_, '_, '_, 'info, MigrateState<'info>>,
681→        bump: u8,
682→        inputs: MigrateLeafParams,
683→    ) -> Result<()> {
684→        let metadata = ctx.accounts.merkle_tree.load()?.metadata;
685→        ForesterEpochPda::check_forester_in_program(
686→            &mut ctx.accounts.registered_forester_pda,
687→            &ctx.accounts.authority.key(),
688→            &ctx.accounts.merkle_tree.key(),
689→            DEFAULT_WORK_V1,
690→        )?;
691→        if metadata.rollover_metadata.network_fee == 0 {
692→            return err!(RegistryError::InvalidNetworkFee);
693→        }
694→        process_migrate_state(&ctx, bump, inputs)
695→    }
696→
697→    /// Creates the config counter PDA
698→    pub fn create_config_counter(ctx: Context<CreateConfigCounter>) -> Result<()> {
699→        ctx.accounts.config_counter.counter += 1;
700→        Ok(())
701→    }
702→
703→    /// Creates a new compressible config
704→    pub fn create_compressible_config(
705→        ctx: Context<CreateCompressibleConfig>,
706→        params: CreateCompressibleConfigData,
707→    ) -> Result<()> {
708→        ctx.accounts
709→            .compressible_config
710→            .set_inner(CompressibleConfig::new_light_token(
711→                ctx.accounts.config_counter.counter,
712→                params.active,
713→                params.update_authority,
714→                params.withdrawal_authority,
715→                params.rent_config,
716→            ));
717→        ctx.accounts.config_counter.counter += 1;
718→        Ok(())
719→    }
720→
721→    /// Updates an existing compressible config
722→    pub fn update_compressible_config(ctx: Context<UpdateCompressibleConfig>) -> Result<()> {
723→        // Update the update_authority if provided
724→        if let Some(authority) = ctx.accounts.new_update_authority.as_ref() {
725→            ctx.accounts.compressible_config.update_authority = authority.key();
726→        }
727→
728→        // Update the withdrawal_authority if provided
729→        if let Some(authority) = ctx.accounts.new_withdrawal_authority.as_ref() {
730→            ctx.accounts.compressible_config.withdrawal_authority = authority.key();
731→        }
732→
733→        Ok(())
734→    }
735→
736→    /// Pauses the compressible config
737→    /// Ctoken accounts created with this config remain operational.
738→    /// Prevents:
739→    /// 1. ctoken account creation (with this config)
740→    /// 2. claiming from rent sponsor
741→    /// 3. witdrawal from rent sponsor
742→    pub fn pause_compressible_config(ctx: Context<UpdateCompressibleConfig>) -> Result<()> {
743→        // Cannot pause a deprecated config
744→        require!(
745→            ctx.accounts.compressible_config.state != CompressibleConfigState::Deprecated as u8,
746→            RegistryError::InvalidConfigState
747→        );
748→        ctx.accounts.compressible_config.state = CompressibleConfigState::Inactive as u8;
749→        Ok(())
750→    }
751→
752→    /// Unpauses the compressible config.
753→    /// Only paused configs (state=0) can be unpaused.
754→    pub fn unpause_compressible_config(ctx: Context<UpdateCompressibleConfig>) -> Result<()> {
755→        require!(
756→            ctx.accounts.compressible_config.state == CompressibleConfigState::Inactive as u8,
757→            RegistryError::InvalidConfigState
758→        );
759→        ctx.accounts.compressible_config.state = CompressibleConfigState::Active as u8;
760→        Ok(())
761→    }
762→
763→    /// Deprecate the compressible config
764→    /// Deprecate means no new ctoken accounts can be created with this config.
765→    /// Other operations are functional.
766→    pub fn deprecate_compressible_config(ctx: Context<UpdateCompressibleConfig>) -> Result<()> {
767→        ctx.accounts.compressible_config.state = CompressibleConfigState::Deprecated as u8;
768→        Ok(())
769→    }
770→
771→    /// Withdraws funds from compressed token pool
772→    pub fn withdraw_funding_pool(ctx: Context<WithdrawFundingPool>, amount: u64) -> Result<()> {
773→        process_withdraw_funding_pool(&ctx, amount)
774→    }
775→
776→    /// Claims rent from compressible token accounts
777→    pub fn claim<'info>(ctx: Context<'_, '_, '_, 'info, ClaimContext<'info>>) -> Result<()> {
778→        // Check forester and track work
779→        // Using [0u8; 32] as the queue pubkey since claim doesn't have a specific queue
780→        ForesterEpochPda::check_forester_in_program(
781→            &mut ctx.accounts.registered_forester_pda,
782→            &ctx.accounts.authority.key(),
783→            &Pubkey::default(),
784→            0,
785→        )?;
786→
787→        // Process the claim CPI
788→        process_claim(&ctx)
789→    }
790→
791→    /// Compress and close token accounts via transfer2
792→    pub fn compress_and_close<'c: 'info, 'info>(
793→        ctx: Context<'_, '_, 'c, 'info, CompressAndCloseContext<'info>>,
794→        authority_index: u8,
795→        destination_index: u8,
796→        indices: Vec<CompressAndCloseIndices>,
797→    ) -> Result<()> {
798→        // Check forester and track work
799→        // Using [0u8; 32] as the queue pubkey since compress_and_close doesn't have a specific queue
800→        ForesterEpochPda::check_forester_in_program(
801→            &mut ctx.accounts.registered_forester_pda,
802→            &ctx.accounts.authority.key(),
803→            &Pubkey::default(),
804→            0,
805→        )?;
806→        process_compress_and_close(&ctx, authority_index, destination_index, indices)
807→    }
808→}
809→
810→/// if registered_forester_pda is not None check forester eligibility and network_fee is not 0
811→/// if metadata.forester == authority can forest
812→/// else throw error
813→pub fn check_forester(
814→    metadata: &MerkleTreeMetadata,
815→    authority: Pubkey,
816→    queue: Pubkey,
817→    registered_forester_pda: &mut Option<Account<'_, ForesterEpochPda>>,
818→    num_work_items: u64,
819→) -> Result<()> {
820→    if let Some(forester_pda) = registered_forester_pda.as_mut() {
821→        // Checks forester:
822→        // - signer
823→        // - eligibility
824→        // - increments work counter
825→        ForesterEpochPda::check_forester_in_program(
826→            forester_pda,
827→            &authority,
828→            &queue,
829→            num_work_items,
830→        )?;
831→        if metadata.rollover_metadata.network_fee == 0 {
832→            return err!(RegistryError::InvalidNetworkFee);
833→        }
834→        Ok(())
835→    } else if metadata.access_metadata.forester == authority {
836→        if metadata.rollover_metadata.network_fee != 0 {
837→            return err!(RegistryError::InvalidNetworkFee);
838→        }
839→        Ok(())
840→    } else {
841→        err!(RegistryError::InvalidSigner)
842→    }
843→}
