    pub fn migrate_state<'info>(
        ctx: Context<'_, '_, '_, 'info, MigrateState<'info>>,
        bump: u8,
        inputs: MigrateLeafParams,
    ) -> Result<()> {
        let metadata = ctx.accounts.merkle_tree.load()?.metadata;
        ForesterEpochPda::check_forester_in_program(
