use account_compression::{utils::constants::GROUP_AUTHORITY_SEED, GroupAuthority};
use light_client::{
    indexer::{AddressMerkleTreeAccounts, StateMerkleTreeAccounts},
    rpc::{Rpc, RpcError},
};
use light_compressed_account::TreeType;
