    pub async fn init_from_acounts(
        payer: &Keypair,
        env: &TestAccounts,
        output_queue_batch_size: usize,
    ) -> Self {
        // Create a vector of StateMerkleTreeAccounts from all v1 and v2 state trees
        let mut state_merkle_tree_accounts = env.v1_state_trees.clone();

        // Add v2 state trees converting from StateMerkleTreeAccountsV2 to StateMerkleTreeAccounts
        for v2_state_tree in &env.v2_state_trees {
            state_merkle_tree_accounts.push(StateMerkleTreeAccounts {
                merkle_tree: v2_state_tree.merkle_tree,
                nullifier_queue: v2_state_tree.output_queue,
                cpi_context: v2_state_tree.cpi_context,
                tree_type: TreeType::StateV2,
            });
        }

        // Create a vector of AddressMerkleTreeAccounts from all v1 address trees
        let mut address_merkle_tree_accounts = env.v1_address_trees.clone();

        // Add v2 address trees (each entry is both the merkle tree and queue)
        for &v2_address_tree in &env.v2_address_trees {
            address_merkle_tree_accounts.push(AddressMerkleTreeAccounts {
                merkle_tree: v2_address_tree,
                queue: v2_address_tree,
            });
        }

        Self::new(
            state_merkle_tree_accounts,
            address_merkle_tree_accounts,
            payer.insecure_clone(),
            env.protocol.group_pda,
            output_queue_batch_size,
        )
        .await
    }

    pub async fn new(
        state_merkle_tree_accounts: Vec<StateMerkleTreeAccounts>,
        address_merkle_tree_accounts: Vec<AddressMerkleTreeAccounts>,
        payer: Keypair,
        group_pda: Pubkey,
        output_queue_batch_size: usize,
    ) -> Self {
        let mut state_merkle_trees = Vec::new();
        for state_merkle_tree_account in state_merkle_tree_accounts.iter() {
            let (tree_type, merkle_tree, output_queue_batch_size) =
                if state_merkle_tree_account.tree_type == TreeType::StateV2 {
                    let merkle_tree = Box::new(MerkleTree::<Poseidon>::new_with_history(
                        DEFAULT_BATCH_STATE_TREE_HEIGHT,
                        0,
                        0,
                        DEFAULT_BATCH_ROOT_HISTORY_LEN,
                    ));
                    (
                        TreeType::StateV2,
                        merkle_tree,
                        Some(output_queue_batch_size),
                    )
                } else {
                    let merkle_tree = Box::new(MerkleTree::<Poseidon>::new_with_history(
                        STATE_MERKLE_TREE_HEIGHT as usize,
                        STATE_MERKLE_TREE_CANOPY_DEPTH as usize,
                        0,
                        STATE_MERKLE_TREE_ROOTS as usize,
                    ));
                    (TreeType::StateV1, merkle_tree, None)
                };

            state_merkle_trees.push(StateMerkleTreeBundle {
                accounts: *state_merkle_tree_account,
                merkle_tree,
                rollover_fee: FeeConfig::default().state_merkle_tree_rollover as i64,
                network_fee: FeeConfig::default().network_fee,
                tree_type,
                output_queue_elements: vec![],
                input_leaf_indices: vec![],
                output_queue_batch_size,
                num_inserted_batches: 0,
            });
        }

        let mut address_merkle_trees = Vec::new();
        for address_merkle_tree_account in address_merkle_tree_accounts {
            address_merkle_trees
                .push(Self::add_address_merkle_tree_bundle(address_merkle_tree_account).unwrap());
        }

        Self {
            state_merkle_trees,
            address_merkle_trees,
            payer,
            compressed_accounts: vec![],
            nullified_compressed_accounts: vec![],
            events: vec![],
            token_compressed_accounts: vec![],
            token_nullified_compressed_accounts: vec![],
            group_pda,
            onchain_pubkey_index: HashMap::new(),
        }
    }

    /// Extract onchain_pubkey from compressed account data if it has the decompressed discriminator.
    /// Compressible accounts store the on-chain PDA pubkey in the first 32 bytes of data.
    fn extract_onchain_pubkey_from_data(
        data: Option<&light_compressed_account::compressed_account::CompressedAccountData>,
    ) -> Option<[u8; 32]> {
        let data = data?;
        // Check discriminator matches DECOMPRESSED_PDA_DISCRIMINATOR
        if data.discriminator == DECOMPRESSED_PDA_DISCRIMINATOR && data.data.len() >= 32 {
            // onchain_pubkey is stored in the first 32 bytes of data (after discriminator)
            data.data[..32].try_into().ok()
        } else {
            None
        }
    }

    /// Find a compressed account by its on-chain pubkey.
    /// This mirrors Photon's lookup by onchain_pubkey column.
    pub fn find_compressed_account_by_onchain_pubkey(
        &self,
        onchain_pubkey: &[u8; 32],
    ) -> Option<&CompressedAccountWithMerkleContext> {
        let matches: Vec<_> = self
            .compressed_accounts
            .iter()
            .filter(|acc| {
                Self::extract_onchain_pubkey_from_data(acc.compressed_account.data.as_ref())
                    .as_ref()
                    == Some(onchain_pubkey)
            })
            .collect();

        debug_assert!(
            matches.len() <= 1,
            "find_compressed_account_by_onchain_pubkey: found {} matches, expected at most 1",
            matches.len()
        );

        matches.into_iter().next()
    }

    /// Find multiple compressed accounts by their on-chain pubkeys.
    pub fn find_multiple_compressed_accounts_by_onchain_pubkeys(
        &self,
        onchain_pubkeys: &[[u8; 32]],
    ) -> Vec<Option<&CompressedAccountWithMerkleContext>> {
        onchain_pubkeys
            .iter()
            .map(|pubkey| self.find_compressed_account_by_onchain_pubkey(pubkey))
            .collect()
    }

    /// Find a token compressed account by its on-chain pubkey.
    pub fn find_token_account_by_onchain_pubkey(
        &self,
        onchain_pubkey: &[u8; 32],
    ) -> Option<&TokenDataWithMerkleContext> {
        let matches: Vec<_> = self
            .token_compressed_accounts
            .iter()
            .filter(|acc| {
                Self::extract_onchain_pubkey_from_data(
                    acc.compressed_account.compressed_account.data.as_ref(),
                )
                .as_ref()
                    == Some(onchain_pubkey)
            })
            .collect();

        debug_assert!(
            matches.len() <= 1,
            "find_token_account_by_onchain_pubkey: found {} matches, expected at most 1",
            matches.len()
        );

        matches.into_iter().next()
    }

    /// Find a compressed account by its PDA pubkey
    pub fn find_compressed_account_by_pda_seed(
        &self,
        pda_pubkey: &[u8; 32],
    ) -> Option<&CompressedAccountWithMerkleContext> {
        // Try each address tree to find an account whose address matches
        for address_tree in &self.address_merkle_trees {
            let tree_pubkey = address_tree.accounts.merkle_tree.to_bytes();

            // For each compressed account with an address, check if it was derived from this seed
            for acc in &self.compressed_accounts {
                if let Some(address) = acc.compressed_account.address {
                    // Try deriving with this tree and the account's owner as program_id
                    let owner_bytes = acc.compressed_account.owner.to_bytes();
                    let derived = light_compressed_account::address::derive_address(
                        pda_pubkey,
                        &tree_pubkey,
                        &owner_bytes,
                    );

                    if derived == address {
                        return Some(acc);
                    }
                }
            }
        }
        None
    }

    /// Find a token compressed account by its PDA pubkey
    pub fn find_token_account_by_pda_seed(
        &self,
        pda_pubkey: &[u8; 32],
    ) -> Option<&TokenDataWithMerkleContext> {
        // Try each address tree to find an account whose address matches
        for address_tree in &self.address_merkle_trees {
            let tree_pubkey = address_tree.accounts.merkle_tree.to_bytes();

            // For each token compressed account with an address, check if it was derived from this seed
            for acc in &self.token_compressed_accounts {
                if let Some(address) = acc.compressed_account.compressed_account.address {
                    // Try deriving with this tree and the account's owner as program_id
                    let owner_bytes = acc.compressed_account.compressed_account.owner.to_bytes();
                    let derived = light_compressed_account::address::derive_address(
                        pda_pubkey,
                        &tree_pubkey,
                        &owner_bytes,
                    );

                    if derived == address {
                        return Some(acc);
                    }
                }
            }
        }
        None
    }

    /// Get the sequence number for a state merkle tree by its pubkey.
    pub fn get_state_tree_seq(&self, tree_pubkey: &Pubkey) -> Option<u64> {
        self.state_merkle_trees
            .iter()
            .find(|tree| tree.accounts.merkle_tree == *tree_pubkey)
            .map(|tree| tree.merkle_tree.sequence_number as u64)
    }

    pub fn add_address_merkle_tree_bundle(
        address_merkle_tree_accounts: AddressMerkleTreeAccounts,
        // TODO: add config here
    ) -> Result<AddressMerkleTreeBundle, IndexerError> {
        if address_merkle_tree_accounts.merkle_tree == address_merkle_tree_accounts.queue {
