        let merkle_tree =
            AccountZeroCopy::<BatchedMerkleTreeMetadata>::new(&mut context, merkle_tree_pubkey)
                .await
                .unwrap();

        let mut queue =
            AccountZeroCopy::<BatchedQueueMetadata>::new(&mut context, output_queue_pubkey)
                .await
