impl<R: Rpc + TestRpc + Indexer, I: Indexer + Clone + TestIndexerExtensions> E2ETestEnv<R, I>
where
    R: Rpc,
    I: Indexer,
{
    pub async fn new(
        mut rpc: R,
        mut indexer: I,
        test_accounts: &TestAccounts,
        keypair_action_config: KeypairActionConfig,
        general_action_config: GeneralActionConfig,
