    }

    {
        println!("pre perform_batch_address_merkle_tree_update");
        for _ in 0..4 {
            perform_batch_address_merkle_tree_update(
                &mut rpc,
                &mut test_indexer,
                &env.protocol.forester,
                &env.protocol.forester.pubkey(),
                &env.v2_address_trees[0],
