        place_holder_c: 0,
        place_holder_d: 0,
        place_holder_e: 0,
        place_holder_f: 0,
    };

    let mainnet_config = ProtocolConfig {
        genesis_slot: 286142505,
        min_weight: 1,
        slot_length: 50,
        registration_phase_length: 216000,
        active_phase_length: 432000,
