    }
    let instruction_params = {
        let merkle_tree =
            get_concurrent_merkle_tree::<StateMerkleTreeAccount, LightProgramTest, Poseidon, 26>(
                &mut rpc,
                test_accounts.v1_state_trees[0].merkle_tree,
